import{_ as e,o as t,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F04: 業外收支純度與收益質量 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F04_業外收支純度與收益質量.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F04_業外收支純度與收益質量.md"}'),i={name:"審計報告庫/財務審計/6239_力成/20260617/F04_業外收支純度與收益質量.md"};function o(n,a,h,s,d,_){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="f04-業外收支純度與收益質量-財務審計專家報告" tabindex="-1">F04: 業外收支純度與收益質量 - 財務審計專家報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-財務審計專家報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>業外收支 (Non-Operating) 規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：業外收支6.60億僅佔稅前淨利7.5%（前年12.1%、2023年32.3%），業外干擾降低獲利純度改善；匯兌從+9.11億轉為-0.82億，業外回歸常態。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>2023-2025年業外收支分別為+38.90億→+12.95億→+6.60億，佔稅前淨利比32.3%→12.1%→7.5%，業外干擾度逐年下降。2025年營業利益81.3億（佔稅前淨利92.5%），本業獲利純度達近年最佳。主要構成：利息收入3.22億（穩定）、其他利益6.10億（含處分資產2.37億為一次性）、財務成本-2.59億、外幣兌換損失-0.82億（較2024年+9.11億大幅反轉）。無匯兌套利或衍生性金融商品投機傾向，業外結構單純可控。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="收益結構透視" tabindex="-1">收益結構透視 <a class="header-anchor" href="#收益結構透視" aria-label="Permalink to &quot;收益結構透視&quot;">​</a></h3><p>2025年業外收支6.60億細項：利息收入3.22億（主要來自現金存款/定存，因力成2025年底前現金餘額約222-164億，利息收入穩定合理）；其他利益及損失6.10億—其中處分不動產廠房設備利益2.37億為一次性（配合設備汰舊換新），剩餘約3.73億為其他營業外利益；權益法認列子公司利益0.50億（2024年損失0.37億）；外幣兌換損失0.82億（主因新台幣升值，力成收美元計價、有自然避險）。財務成本2.59億（長期借款利息，2025年長債增加）。</p><p>扣除一次性處分利益2.37億與匯兌損失0.82億後，常態性業外約5.05億，對應稅前淨利8,792M，常態業外佔比僅5.7%，獲利純度極高。</p><h3 id="雜訊敏感度分析" tabindex="-1">雜訊敏感度分析 <a class="header-anchor" href="#雜訊敏感度分析" aria-label="Permalink to &quot;雜訊敏感度分析&quot;">​</a></h3><p>匯兌波動是力成業外最大的「雜訊」來源。2023年匯兌+1.12億、2024年匯兌+9.11億、2025年匯兌-0.82億，波動幅度達年±10億等級。預估台幣每變動1元對力成年淨利的邊際影響約3-5億（按自然避險後的曝險部位估算）。2026年若新台幣維持升值趨勢，匯兌可能持續為負貢獻，但金額可控（&lt;1億）。</p><h3 id="可持續性評價" tabindex="-1">可持續性評價 <a class="header-anchor" href="#可持續性評價" aria-label="Permalink to &quot;可持續性評價&quot;">​</a></h3><p>力成的業外結構正在改善：2023年高達32.3%的業外佔比（主因其他利益37.70億，應為一次性收益如處分西安廠或其他資產）後，2024年降至12.1%，2025年進一步降至7.5%。當前業外的利息收入與權益法收益具有常態性，一次性項目逐年減少。預估2026年業外佔比可維持在5-10%的低干擾區間。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>匯兌波動風險未消</strong>：匯兌從2024年+9.11億轉為2025年-0.82億，波動約10億。若台幣持續強勢，可能持續負向影響。</li><li><strong>一次性收益基底效應</strong>：2023年業外高達38.90億墊高基期。推算2026年常態性EPS應設定業外5-10億區間，以免過度樂觀。</li><li><strong>金融評價依存市場</strong>：金融資產評價利益3.90億（佔業外59.1%），全球股市波動加劇時可能轉為損失，對EPS產生0.2-0.3元衝擊。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>業外佔比降至最低</strong>：從32.3%（2023年）降至7.5%（2025年），長趨勢向下。業外從「干擾項」轉為「穩定項」。</li><li><strong>自然避險完善</strong>：美元資產（AR/存款~60-70%）自然抵銷美元負債，外幣兌換可控，非投機交易。</li><li><strong>權益法關聯穩定獲利</strong>：權益法利益0.50億（2024年損失0.37億），投資晶成能源等策略性標的，與半導體產業鏈相關。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>獲利結構持續改善，至2025年業外佔比僅7.5%，純度穩健。匯兌波動存在但非投機。EPS可信度高，無激進會計或一次性虛胖風險。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (finance 6239)</li><li>原始數據：FinMind TaiwanStockFinancialStatements</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (page 9，綜合損益表)</li><li>年報數據：2024_Q4_6239_合併.pdf (page 9，綜合損益表)</li><li>數據查詢日期：2026-06-17</li></ul>',24)])])}const p=e(i,[["render",o]]);export{u as __pageData,p as default};
